import type { MouseEvent } from 'react';

/** Open ERP list row action menu at pointer (Ctrl+click / context menu). */
export function openListRowMenu<T extends { id: string }>(
  e: MouseEvent,
  row: T,
  onSelectRow: (row: T) => void,
  setRowMenu: (value: { x: number; y: number; row: T } | null) => void,
): void {
  e.preventDefault();
  e.stopPropagation();
  onSelectRow(row);
  setRowMenu({ x: e.clientX, y: e.clientY, row });
}
